import 'package:cloud_firestore/cloud_firestore.dart'; import 'package:flutter/material.dart'; import '../services/firestore_service.dart';
class EventsScreen extends StatelessWidget { const EventsScreen({super.key}); @override Widget build(BuildContext context){ final service=FirestoreService(); return Scaffold(appBar: AppBar(title: const Text('Events')), body: StreamBuilder<QuerySnapshot<Map<String,dynamic>>>(stream: service.streamCollection('events'), builder:(context,snapshot){ if(snapshot.hasError) return Center(child: Text('Error: ${snapshot.error}')); if(!snapshot.hasData) return const Center(child:CircularProgressIndicator()); final docs=snapshot.data!.docs; if(docs.isEmpty) return const Center(child:Text('No events available.')); return ListView.builder(padding: const EdgeInsets.all(16), itemCount: docs.length, itemBuilder:(context,index){ final d=docs[index].data(); return Card(child: ListTile(leading: const Icon(Icons.event,color:Colors.teal), title: Text(d['title']??'Untitled Event'), subtitle: Text('${d['description']??''}\n${d['eventDate']??'-'} | ${d['startTime']??'-'} - ${d['endTime']??'-'}'), isThreeLine:true)); }); })); } }
